mapper.select:
select count(*) from class
user_num = #{userNum}
and cla_title like '%' || #{pageMaker.keyword} || '%'

mapper.update:

	update class set
	cla_views = cla_views+1
	where cla_num = #{claNum}

mapper.select:
SELECT u.* FROM users u INNER JOIN classapply ca ON u.user_num = ca.user_num WHERE ca.cla_num = #{claNum}
AND ( u.user_name LIKE '%' || #{pageMaker.keyword} || '%' OR u.user_email LIKE '%' || #{pageMaker.keyword} || '%' )
ORDER BY u.user_name ASC

mapper.update:
UPDATE class SET
    cla_startdate = TO_DATE(#{eduStart}, 'YYYY-MM-DD'),
    cla_enddate   = TO_DATE(#{eduEnd},   'YYYY-MM-DD'),
    cla_maxstu    = #{maxStudents},
    cla_complete  = #{completeCondition}
WHERE cla_num = #{courseNo}
